import java.util.*;

public class PositiveIntegers {
    public static List<Integer> getPositiveInts(int[] arr) {
        return Arrays.stream(arr)
                    .filter(i -> i > 0)
                    .collect(Collectors.toList());
    }

    public static void main(String[] args) {
        int[] arr = {5, -2, 0, 8};
        System.out.println(getPositiveInts(arr));  // [5, 8]
    }
}
