import java.util.*;

public class PositiveIntegersGeneric {
    public static List<Integer> getPositiveInts(Object[] arr) {
        List<Integer> result = new ArrayList<>();
        for (Object o : arr) {
            if (o instanceof Integer iVal && iVal > 0) {
                result.add((Integer) o);
            } else if (o instanceof Number n && n.intValue() > 0) {
                result.add(n.intValue());
            }
        }
        return result;
    }
}
